const sqlite3 = require('sqlite3').verbose();
const path = '/Users/philliplowe/.openclaw/workspaces/sol/utopia-deli-revamp/orders.db';
const body = $json.body;

return new Promise((resolve) => {
  const db = new sqlite3.Database(path, (err) => {
    if (err) { resolve({ json: { error: err.message } }); return; }
    db.run(
      'INSERT INTO orders (order_id, customer_name, customer_email, customer_phone, customer_city, customer_county, cart_json, subtotal_cents, tax_cents, total_cents, square_payment_link, status) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)',
      ['TEST-' + Date.now(), body.name, body.email, body.phone, 'LR', 'Pulaski', '[]', 100, 10, 110, 'https://test.com', 'pending'],
      function(err) {
        if (err) resolve({ json: { error: err.message } });
        else resolve({ json: { saved: true, rowid: this.lastID } });
        db.close();
      }
    );
  });
});
